// Junta os campos adicionais de Lead e Negocio em uma unica saida
// com colunas estaveis (escopo, id, name, type, options...) para copia.

function extrair(resposta) {
  if (!resposta) return [];
  if (Array.isArray(resposta)) return resposta;
  return resposta.data || resposta.items || resposta.results || [];
}

function normalizar(campo, escopo) {
  return {
    escopo,
    id: campo.id,
    name: campo.name,
    label: campo.label || campo.name,
    type: campo.type || campo.fieldType,
    required: campo.required ?? campo.isRequired ?? false,
    options: campo.options || campo.values || campo.choices || null,
    raw: campo,
  };
}

const leadResp = $('Campos Adicionais - Lead').first()?.json;
const dealResp = $('Campos Adicionais - Negocio').first()?.json;

const leadFields = extrair(leadResp).map((c) => normalizar(c, 'lead'));
const dealFields = extrair(dealResp).map((c) => normalizar(c, 'deal'));

const todos = [...leadFields, ...dealFields];

// Se nao houver nenhum campo, retorna um item indicativo
if (todos.length === 0) {
  return [{
    json: {
      aviso: 'Nenhum campo adicional cadastrado no DataCrazy.',
      leadRaw: leadResp,
      dealRaw: dealResp,
    },
  }];
}

return todos.map((item) => ({ json: item }));
